    78	func (n *Nftables) gatherTable(acc telegraf.Accumulator, name string) error {
    79		// Run the nft command
    80		args := append(n.args, name)
    81		c := exec.Command(n.Binary, args...)
    82		out, err := c.Output()
    83		if err != nil {
    84			var oserr *exec.ExitError
    85			if errors.As(err, &oserr) {
    86				buf, _, _ := bytes.Cut(oserr.Stderr, []byte("\n"))
    87				msg := string(bytes.TrimSpace(buf))
    88				if msg == "Error: No such file or directory" {
    89					return fmt.Errorf("table %q does not exist", name)
    90				}
    91				return fmt.Errorf("error executing nft command: %w (%s)", err, msg)
    92			}
    93			return fmt.Errorf("error executing nft command: %w", err)
    94		}
