    96		// Parse the result into metrics and add them to the accumulator
    97		var nftable table
    98		if err := json.Unmarshal(out, &nftable); err != nil {
    99			return fmt.Errorf("parsing command output failed: %w", err)
   100		}
   101	
   102		for _, include := range n.Include {
   103			switch include {
   104			case "anonymous-counters":
   105				for _, rule := range nftable.Rules {
   106					if len(rule.Comment) == 0 {
   107						continue
   108					}
   109					for _, expr := range rule.Exprs {
   110						if expr.Cntr == nil || expr.Cntr.isNamedRef {
   111							continue
   112						}
   113						fields := map[string]interface{}{
   114							"bytes": expr.Cntr.Bytes,
   115							"pkts":  expr.Cntr.Packets,
   116						}
   117						tags := map[string]string{
   118							"table": rule.Table,
   119							"chain": rule.Chain,
   120							"rule":  rule.Comment,
   121						}
   122						acc.AddFields("nftables", fields, tags)
   123					}
   124				}
   125			case "counters":
   126				for _, counter := range nftable.Counters {
   127					fields := map[string]interface{}{
   128						"bytes": counter.Bytes,
   129						"pkts":  counter.Packets,
   130					}
   131					tags := map[string]string{
   132						"table":   counter.Table,
   133						"counter": counter.Name,
   134					}
   135					acc.AddFields("nftables", fields, tags)
   136				}
   137			case "sets":
   138				for _, set := range nftable.Sets {
   139					fields := map[string]interface{}{
   140						"count": len(set.Elem),
   141					}
   142					tags := map[string]string{
   143						"table": set.Table,
   144						"set":   set.Name,
   145					}
   146					acc.AddFields("nftables", fields, tags)
   147				}
   148			}
   149		}
   150		return nil
   151	}
   152	
   153	func init() {
   154		inputs.Add("nftables", func() telegraf.Input {
   155			return &Nftables{}
   156		})
   157	}
