cd /workspace/telegraf && cat > /tmp/repro_test.go << 'EOF'
package main

import (
	"encoding/json"
	"fmt"
)

type namedSet struct {
	Family string `json:"family"`
	Name   string `json:"name"`
	Table  string `json:"table"`
	Elem   []elem `json:"elem,omitempty"`
}

type elem struct{}

func main() {
	// This is the format that causes the error - plain strings in elem array
	jsonStr := `{
		"set": {
			"family": "inet",
			"name": "AllowedIPs",
			"table": "firewall",
			"type": "ipv4_addr",
			"handle": 18,
			"flags": ["interval"],
			"elem": ["10.47.55.250", "10.47.56.232"]
		}
	}`

	var rawTable map[string]json.RawMessage
	if err := json.Unmarshal([]byte(jsonStr), &rawTable); err != nil {
		fmt.Printf("Error unmarshaling raw table: %v\n", err)
		return
	}

	var s namedSet
	if err := json.Unmarshal(rawTable["set"], &s); err != nil {
		fmt.Printf("Error unmarshaling set: %v\n", err)
	} else {
		fmt.Printf("Success! Set: %+v, Elem count: %d\n", s, len(s.Elem))
	}

	// Also test with object format (existing format)
	jsonStr2 := `{
		"set": {
			"family": "inet",
			"name": "test_set",
			"table": "test",
			"type": "ipv6_addr",
			"handle": 6,
			"elem": [
				{"elem": {"val": "::1", "expires": 99}},
				{"elem": {"val": "::2", "expires": 277}}
			]
		}
	}`

	var rawTable2 map[string]json.RawMessage
	if err := json.Unmarshal([]byte(jsonStr2), &rawTable2); err != nil {
		fmt.Printf("Error unmarshaling raw table 2: %v\n", err)
		return
	}

	var s2 namedSet
	if err := json.Unmarshal(rawTable2["set"], &s2); err != nil {
		fmt.Printf("Error unmarshaling set 2: %v\n", err)
	} else {
		fmt.Printf("Success 2! Set: %+v, Elem count: %d\n", s2, len(s2.Elem))
	}
}
EOF
cd /workspace/telegraf && go run /tmp/repro_test.go 2>&1

