    45				}
    46				nftable.Counters = append(nftable.Counters, &c)
    47			} else if _, found := nfthing["set"]; found {
    48				var s namedSet
    49				if err := json.Unmarshal(nfthing["set"], &s); err != nil {
    50					return fmt.Errorf("unable to parse set: %w", err)
    51				}
    52				nftable.Sets = append(nftable.Sets, &s)
    53			}
    54		}
    55		return nil
    56	}
