    81	// UnmarshalJSON handles both anonymous counters (objects with packets/bytes)
    82	// and named counter references (strings). Named references are marked with
    83	// isNamedRef flag since they don't contain inline statistics.
    84	func (c *anonymousCounter) UnmarshalJSON(b []byte) error {
    85		if len(b) > 0 && b[0] == '"' {
    86			// Named counter reference - mark it and return
    87			c.isNamedRef = true
    88			return nil
    89		}
    90		// Anonymous counter - parse the object using type alias to avoid
    91		// infinite recursion (alias has no methods, so json.Unmarshal uses
    92		// default struct unmarshaling instead of calling this method again)
    93		type anonymousCounterAlias anonymousCounter
    94		return json.Unmarshal(b, (*anonymousCounterAlias)(c))
    95	}
