   112	type elem struct{}
   113	
   114	// UnmarshalJSON handles both string elements (predefined sets) and
   115	// object elements (dynamic sets). The plugin only uses the count of
   116	// elements, so we just need to accept either format.
   117	func (e *elem) UnmarshalJSON(b []byte) error {
   118		if len(b) > 0 && b[0] == '"' {
   119			// String element from predefined sets - consume and return
   120			return nil
   121		}
   122		// Object element from dynamic sets - consume the object
   123		var raw json.RawMessage
   124		return json.Unmarshal(b, &raw)
   125	}
